// Discovery-Input normalisieren + validieren. Niemals throw -> Fehler-Flag statt Crash.
const cfg = $input.first().json;
const body = cfg.body ?? cfg;

const clean = (v, max) => (typeof v === 'string' ? v.trim().slice(0, max) : '');

const clientName = clean(body.clientName, 120);
const clientCompany = clean(body.clientCompany, 200);
const clientEmail = clean(body.clientEmail, 200).toLowerCase();
const notes = clean(body.notes, 6000);
const requestedScope = clean(body.requestedScope, 1000);
const budgetHint = body.budgetHint != null ? Number(body.budgetHint) || null : null;
const deadline = clean(body.deadline, 40);

// Tage bis Deadline (fuer Rush-Surcharge); null wenn unparsbar
let daysToDeadline = null;
if (deadline) {
  const d = new Date(deadline);
  if (!isNaN(d.getTime())) {
    daysToDeadline = Math.ceil((d.getTime() - Date.now()) / 86400000);
  }
}

const emailOk = /^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(clientEmail);
const notesOk = notes.length >= 40; // genug Substanz fuer ein Angebot
const valid = !!clientName && !!clientCompany && emailOk && notesOk;

const reasons = [];
if (!clientName) reasons.push('clientName fehlt');
if (!clientCompany) reasons.push('clientCompany fehlt');
if (!emailOk) reasons.push('clientEmail ungueltig');
if (!notesOk) reasons.push('Discovery-Notizen zu kurz (<40 Zeichen)');

return [{
  json: {
    valid,
    invalidReasons: reasons,
    clientName,
    clientCompany,
    clientEmail,
    notes,
    requestedScope,
    budgetHint,
    deadline,
    daysToDeadline,
    receivedAt: new Date().toISOString(),
    config: {
      vendorName: cfg.vendorName,
      vendorCompany: cfg.vendorCompany,
      vendorAddress: cfg.vendorAddress,
      vendorEmail: cfg.vendorEmail,
      serviceCatalog: cfg.serviceCatalog,
      pricingRules: cfg.pricingRules,
      notifyEmail: cfg.notifyEmail,
      pdfRenderUrl: cfg.pdfRenderUrl,
      proposalStoreUrl: cfg.proposalStoreUrl,
      sendMode: cfg.sendMode
    }
  }
}];

// LLM-JSON robust parsen + deterministische Pricing-Logik anwenden. Niemals throw.
const base = $('Code: Discovery normalisieren').item.json;
const cfg = base.config;
const catalog = cfg.serviceCatalog || {};
const rules = cfg.pricingRules || {};
const raw = $input.first().json;
const text = raw.output ?? raw.text ?? raw.response ?? JSON.stringify(raw);

let parsed = { summary: '', identifiedNeeds: [], lineItems: [], deliverables: [], recommendedScope: 'standard', dataGaps: ['llm_parse_failed'] };
try {
  const m = (typeof text === 'string' ? text : JSON.stringify(text)).match(/\{[\s\S]*\}/);
  if (m) parsed = { ...parsed, ...JSON.parse(m[0]) };
} catch (e) {
  parsed.dataGaps = ['llm_parse_error: ' + e.message];
}

// Nur Positionen mit gueltigem Katalog-Key behalten
const rawItems = Array.isArray(parsed.lineItems) ? parsed.lineItems : [];
const lineItems = rawItems
  .filter(li => li && catalog[li.key])
  .map(li => {
    const cat = catalog[li.key];
    const qty = Math.max(1, parseInt(li.quantity, 10) || 1);
    const lineTotal = cat.basePrice * qty;
    return { key: li.key, label: cat.label, unit: cat.unit, unitPrice: cat.basePrice, quantity: qty, justification: li.justification || '', lineTotal };
  });

// Fallback: wenn LLM keine gueltige Position lieferte -> Workshop als Mindest-Angebot
if (lineItems.length === 0 && catalog.workshop) {
  lineItems.push({ key: 'workshop', label: catalog.workshop.label, unit: catalog.workshop.unit, unitPrice: catalog.workshop.basePrice, quantity: 1, justification: 'Automatischer Fallback: Scope unklar, Discovery-Workshop empfohlen.', lineTotal: catalog.workshop.basePrice });
  parsed.dataGaps = [...(parsed.dataGaps || []), 'no_valid_line_items_from_llm'];
}

const subtotal = lineItems.reduce((s, li) => s + li.lineTotal, 0);

// Volumen-Rabatt
let volumeDiscount = 0;
if (rules.volumeDiscountThreshold && subtotal >= rules.volumeDiscountThreshold) {
  volumeDiscount = Math.round(subtotal * (rules.volumeDiscountPct || 0));
}

// Rush-Surcharge bei knapper Deadline
let rushSurcharge = 0;
const rushApplies = base.daysToDeadline != null && rules.rushThresholdDays && base.daysToDeadline >= 0 && base.daysToDeadline <= rules.rushThresholdDays;
if (rushApplies) {
  rushSurcharge = Math.round((subtotal - volumeDiscount) * (rules.rushSurchargePct || 0));
}

const netTotal = Math.max(0, subtotal - volumeDiscount + rushSurcharge);
const vatRate = rules.vatRate || 0;
const vatAmount = Math.round(netTotal * vatRate);
const grossTotal = netTotal + vatAmount;
const deposit = Math.round(grossTotal * (rules.depositPct || 0));

// Budget-Flag: Angebot deutlich ueber genanntem Budget?
const budgetWarning = base.budgetHint && grossTotal > base.budgetHint * 1.15;

const proposalId = 'AG-' + new Date().getFullYear() + '-' + Date.now().toString().slice(-6);
const validUntil = new Date(Date.now() + (rules.validityDays || 14) * 86400000).toISOString().slice(0, 10);

return [{
  json: {
    proposalId,
    clientName: base.clientName,
    clientCompany: base.clientCompany,
    clientEmail: base.clientEmail,
    summary: parsed.summary,
    identifiedNeeds: parsed.identifiedNeeds || [],
    deliverables: parsed.deliverables || [],
    recommendedScope: parsed.recommendedScope || 'standard',
    lineItems,
    pricing: {
      currency: rules.currency || 'EUR',
      subtotal,
      volumeDiscount,
      rushSurcharge,
      rushApplied: !!rushApplies,
      netTotal,
      vatRate,
      vatAmount,
      vatNote: rules.vatNote || '',
      grossTotal,
      deposit,
      depositPct: rules.depositPct || 0
    },
    budgetWarning: !!budgetWarning,
    validUntil,
    dataGaps: parsed.dataGaps || [],
    receivedAt: base.receivedAt,
    generatedAt: new Date().toISOString(),
    config: cfg
  }
}];

// Angebots-HTML rendern (deterministisch, kein LLM). Liefert html + plaintext fuer PDF + Mail.
const p = $input.first().json;
const cfg = p.config;
const fmt = (n) => new Intl.NumberFormat('de-DE', { style: 'currency', currency: p.pricing.currency }).format(n);
const esc = (s) => String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

const rows = p.lineItems.map(li =>
  `<tr><td style="padding:8px;border-bottom:1px solid #eee;">${esc(li.label)}<br><span style="font-size:11px;color:#888;">${esc(li.justification)}</span></td>` +
  `<td style="padding:8px;border-bottom:1px solid #eee;text-align:center;">${li.quantity} ${esc(li.unit)}</td>` +
  `<td style="padding:8px;border-bottom:1px solid #eee;text-align:right;">${fmt(li.unitPrice)}</td>` +
  `<td style="padding:8px;border-bottom:1px solid #eee;text-align:right;">${fmt(li.lineTotal)}</td></tr>`
).join('');

const pr = p.pricing;
const adjustmentRows = [];
if (pr.volumeDiscount > 0) adjustmentRows.push(`<tr><td colspan="3" style="padding:4px 8px;text-align:right;color:#2ea043;">Mengenrabatt</td><td style="padding:4px 8px;text-align:right;color:#2ea043;">- ${fmt(pr.volumeDiscount)}</td></tr>`);
if (pr.rushSurcharge > 0) adjustmentRows.push(`<tr><td colspan="3" style="padding:4px 8px;text-align:right;color:#cf6b22;">Express-Zuschlag</td><td style="padding:4px 8px;text-align:right;color:#cf6b22;">+ ${fmt(pr.rushSurcharge)}</td></tr>`);
if (pr.vatAmount > 0) adjustmentRows.push(`<tr><td colspan="3" style="padding:4px 8px;text-align:right;color:#666;">USt (${Math.round(pr.vatRate*100)}%)</td><td style="padding:4px 8px;text-align:right;color:#666;">${fmt(pr.vatAmount)}</td></tr>`);

const needs = (p.identifiedNeeds || []).map(n => `<li>${esc(n)}</li>`).join('');
const delis = (p.deliverables || []).map(d => `<li>${esc(d)}</li>`).join('');

const html = `<!DOCTYPE html><html lang="de"><head><meta charset="utf-8"><style>body{font-family:Arial,Helvetica,sans-serif;color:#222;max-width:720px;margin:0 auto;padding:32px;line-height:1.55;}h1{font-size:22px;margin:0 0 4px;}h2{font-size:15px;margin:24px 0 8px;border-bottom:2px solid #1f6feb;padding-bottom:4px;}table{border-collapse:collapse;width:100%;font-size:13px;}.muted{color:#888;font-size:12px;}.total{font-size:18px;font-weight:bold;}</style></head><body>` +
`<div style="display:flex;justify-content:space-between;align-items:flex-start;"><div><h1>Angebot</h1><p class="muted">Nr. ${esc(p.proposalId)} &middot; ${new Date(p.generatedAt).toLocaleDateString('de-DE')}</p></div>` +
`<div style="text-align:right;"><strong>${esc(cfg.vendorCompany)}</strong><br><span class="muted">${esc(cfg.vendorAddress)}<br>${esc(cfg.vendorEmail)}</span></div></div>` +
`<h2>Fuer</h2><p><strong>${esc(p.clientCompany)}</strong><br>${esc(p.clientName)} &middot; ${esc(p.clientEmail)}</p>` +
`<h2>Ausgangslage</h2><p>${esc(p.summary)}</p>` +
(needs ? `<ul>${needs}</ul>` : '') +
`<h2>Leistungen & Investition</h2><table><thead><tr style="text-align:left;color:#666;font-size:12px;"><th style="padding:8px;">Position</th><th style="padding:8px;text-align:center;">Menge</th><th style="padding:8px;text-align:right;">Einzel</th><th style="padding:8px;text-align:right;">Summe</th></tr></thead><tbody>${rows}` +
`<tr><td colspan="3" style="padding:8px;text-align:right;">Zwischensumme</td><td style="padding:8px;text-align:right;">${fmt(pr.subtotal)}</td></tr>${adjustmentRows.join('')}` +
`<tr><td colspan="3" style="padding:12px 8px;text-align:right;" class="total">Gesamt</td><td style="padding:12px 8px;text-align:right;" class="total">${fmt(pr.grossTotal)}</td></tr></tbody></table>` +
(pr.vatNote ? `<p class="muted">${esc(pr.vatNote)}</p>` : '') +
`<p class="muted">Anzahlung bei Auftragserteilung: ${fmt(pr.deposit)} (${Math.round(pr.depositPct*100)}%).</p>` +
`<h2>Liefer-Ergebnisse</h2><ul>${delis}</ul>` +
`<h2>Konditionen</h2><p class="muted">Angebot gueltig bis ${esc(p.validUntil)}. Preise in ${esc(pr.currency)}. Dieses Angebot wurde KI-gestuetzt aus den Discovery-Notizen erstellt und vor Versand geprueft.</p>` +
`<hr style="border:none;border-top:1px solid #eee;margin:24px 0;"><p class="muted">${esc(cfg.vendorName)} &middot; ${esc(cfg.vendorCompany)} &middot; ${esc(cfg.vendorAddress)} &middot; ${esc(cfg.vendorEmail)}</p>` +
`</body></html>`;

const plaintext = `Angebot ${p.proposalId}\nFuer: ${p.clientCompany} (${p.clientName})\n\nAusgangslage:\n${p.summary}\n\nLeistungen:\n` +
  p.lineItems.map(li => `- ${li.label} x${li.quantity}: ${fmt(li.lineTotal)}`).join('\n') +
  `\n\nGesamt: ${fmt(pr.grossTotal)}\nAnzahlung: ${fmt(pr.deposit)}\nGueltig bis: ${p.validUntil}`;

return [{ json: { ...p, html, plaintext } }];
